-- UUID Key:
-- d0000000 = department (hex valid)
-- a0000000 = program   (was p, invalid hex)
-- f0000000 = faculty   (hex valid)
-- 50000000 = students  (was s, invalid hex)
-- 5b000000 = subject   (was sub, invalid hex)
-- c0000001 = COs       (hex valid)
-- b0000001 = POs       (was po, invalid hex)

-- 0. Cleanup (defensive — uses DO blocks to handle missing columns/tables)
DO $$ BEGIN
    DELETE FROM student_co_marks WHERE subject_id = '5b000000-0000-0000-0000-000000000001';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

DO $$ BEGIN
    DELETE FROM co_po_mapping WHERE subject_id = '5b000000-0000-0000-0000-000000000001';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

DO $$ BEGIN
    DELETE FROM co_pso_mapping WHERE subject_id = '5b000000-0000-0000-0000-000000000001';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

DO $$ BEGIN
    DELETE FROM student_subjects WHERE subject_id = '5b000000-0000-0000-0000-000000000001';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

DO $$ BEGIN
    DELETE FROM faculty_subjects WHERE subject_id = '5b000000-0000-0000-0000-000000000001';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

DO $$ BEGIN
    DELETE FROM course_outcomes WHERE subject_id = '5b000000-0000-0000-0000-000000000001';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

DO $$ BEGIN
    DELETE FROM co_attainment_results WHERE subject_id = '5b000000-0000-0000-0000-000000000001';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

DO $$ BEGIN
    DELETE FROM po_attainment_results WHERE subject_id = '5b000000-0000-0000-0000-000000000001';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

DO $$ BEGIN
    DELETE FROM pso_attainment_results WHERE subject_id = '5b000000-0000-0000-0000-000000000001';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

DO $$ BEGIN
    DELETE FROM subjects WHERE code = 'PH3151';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

DO $$ BEGIN
    DELETE FROM users WHERE email LIKE 'student%@test.copo.in';
    DELETE FROM users WHERE email = 'kumar@test.copo.in';
EXCEPTION WHEN undefined_column THEN NULL; WHEN undefined_table THEN NULL; END $$;

-- 1. CSE department
VALUES ('d0000000-0000-0000-0000-000000000001', 'Computer Science Engineering', 'CSE')
ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name;

-- 2. CSE program (use 'a' prefix — 'p' is not valid hex!)
VALUES ('a0000000-0000-0000-0000-000000000001', 'B.Tech Computer Science Engineering', 'CSE', 'd0000000-0000-0000-0000-000000000001')
ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name;

-- 3. Faculty (Dr. Kumar)
VALUES ('f0000000-0000-0000-0000-000000000001', 'Dr. Kumar', 'kumar@test.copo.in', 'FACULTY', 'd0000000-0000-0000-0000-000000000001', 'F001')
ON CONFLICT (email) DO UPDATE SET name = EXCLUDED.name, role = EXCLUDED.role, department_id = EXCLUDED.department_id, register_no = EXCLUDED.register_no;

-- 4. 10 Students (use '5' prefix — 's' is not valid hex!)
ON CONFLICT (email) DO UPDATE SET name = EXCLUDED.name, role = EXCLUDED.role, department_id = EXCLUDED.department_id, year = EXCLUDED.year, register_no = EXCLUDED.register_no;

-- 5. Subject: Engineering Physics (use '5b' prefix — 'sub' is not valid hex!)
VALUES ('5b000000-0000-0000-0000-000000000001', 'Engineering Physics', 'PH3151', 4, 2, 4, 'a0000000-0000-0000-0000-000000000001', 25, 15)
ON CONFLICT DO NOTHING;

-- 6. Faculty assignment
VALUES ('f0000000-0000-0000-0000-000000000001', '5b000000-0000-0000-0000-000000000001', '2025-26')
ON CONFLICT DO NOTHING;

-- 7. Course Outcomes (cutoff = 12) — 'c' is valid hex
ON CONFLICT DO NOTHING;

-- 8. Enroll all 10 students
ON CONFLICT DO NOTHING;

-- 9. Program Outcomes (12 POs) — use 'b0' prefix ('po' is invalid hex because of 'p')
ON CONFLICT DO NOTHING;

-- 10. CO-PO Mapping (non-zero values only)
ON CONFLICT (subject_id, co_number, po_number) DO UPDATE SET mapping_value = EXCLUDED.mapping_value;

-- 11. CO-PSO Mapping (2 PSOs)
ON CONFLICT (subject_id, co_number, pso_number) DO UPDATE SET mapping_value = EXCLUDED.mapping_value;

-- 12. Student Marks (10 students × 5 COs = 50 rows)
ON CONFLICT (student_id, subject_id, co_number, academic_year) DO UPDATE SET marks = EXCLUDED.marks, lab_marks = EXCLUDED.lab_marks, assignment_marks = EXCLUDED.assignment_marks;

-- Verification
SELECT 'Sample data inserted!' AS status,
       (SELECT count(*) FROM users WHERE email LIKE '%@test.copo.in') AS test_users,
       (SELECT count(*) FROM student_co_marks WHERE subject_id = '5b000000-0000-0000-0000-000000000001') AS marks,
       (SELECT count(*) FROM co_po_mapping WHERE subject_id = '5b000000-0000-0000-0000-000000000001') AS mappings;
